/**
 * Auth Store
 *
 * MobX authentication store with localStorage persistence.
 * Generated by @shogo-ai/sdk - DO NOT EDIT DIRECTLY
 */

import { makeAutoObservable, runInAction } from 'mobx'

const API_BASE = '/api'
const STORAGE_KEY = 'shogo-auth-user'

// ============================================================================
// Types
// ============================================================================

export interface AuthUser {
  id: string
  email: string
  createdAt: string | Date
  updatedAt: string | Date
}

export interface SignUpInput {
  email: string
  password?: string
}

export interface SignInInput {
  email: string
  password?: string
}

// ============================================================================
// AuthStore
// ============================================================================

export class AuthStore {
  user: AuthUser | null = null
  isLoading = false
  error: string | null = null

  constructor() {
    makeAutoObservable(this)
    this.loadFromStorage()
  }

  // === Getters ===

  get isAuthenticated(): boolean {
    return this.user !== null
  }

  get userId(): string | null {
    return this.user?.id ?? null
  }

  // === Storage ===

  private loadFromStorage() {
    try {
      if (typeof window === "undefined") return
      const stored = localStorage.getItem(STORAGE_KEY)
      if (stored) {
        this.user = JSON.parse(stored)
      }
    } catch {
      // Ignore storage errors
    }
  }

  private saveToStorage(user: AuthUser | null) {
    try {
      if (typeof window === "undefined") return
      if (user) {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(user))
      } else {
        localStorage.removeItem(STORAGE_KEY)
      }
    } catch {
      // Ignore storage errors
    }
  }

  // === Actions ===

  /**
   * Sign in with email
   * Looks up user by email in the database
   */
  async signIn(input: SignInInput): Promise<AuthUser> {
    this.isLoading = true
    this.error = null

    try {
      // Find user by email
      const res = await fetch(`${API_BASE}/users?email=${encodeURIComponent(input.email)}`)
      const data = await res.json()

      if (!data.ok) {
        throw new Error(data.error?.message || 'Failed to sign in')
      }

      const users = data.items || []
      if (users.length === 0) {
        throw new Error('No account found with this email. Please sign up first.')
      }

      const user = users[0] as AuthUser

      runInAction(() => {
        this.user = user
        this.isLoading = false
        this.saveToStorage(user)
      })

      return user
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Sign in failed'
      runInAction(() => {
        this.error = message
        this.isLoading = false
      })
      throw err
    }
  }

  /**
   * Sign up with email
   * Creates a new user in the database
   */
  async signUp(input: SignUpInput): Promise<AuthUser> {
    this.isLoading = true
    this.error = null

    try {
      // Check if user already exists
      const checkRes = await fetch(`${API_BASE}/users?email=${encodeURIComponent(input.email)}`)
      const checkData = await checkRes.json()

      if (checkData.ok && checkData.items?.length > 0) {
        throw new Error('An account with this email already exists. Please sign in.')
      }

      // Create new user
      const res = await fetch(`${API_BASE}/users`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          email: input.email,
        }),
      })
      const data = await res.json()

      if (!data.ok) {
        throw new Error(data.error?.message || 'Failed to create account')
      }

      const user = data.data as AuthUser

      runInAction(() => {
        this.user = user
        this.isLoading = false
        this.saveToStorage(user)
      })

      return user
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Sign up failed'
      runInAction(() => {
        this.error = message
        this.isLoading = false
      })
      throw err
    }
  }

  /**
   * Sign out
   * Clears user from state and localStorage
   */
  signOut() {
    this.user = null
    this.error = null
    this.saveToStorage(null)
  }

  /**
   * Clear error state
   */
  clearError() {
    this.error = null
  }

  /**
   * Refresh user data from server
   */
  async refresh(): Promise<AuthUser | null> {
    if (!this.user) return null

    try {
      const res = await fetch(`${API_BASE}/users/${this.user.id}`)
      const data = await res.json()

      if (data.ok && data.data) {
        runInAction(() => {
          this.user = data.data
          this.saveToStorage(data.data)
        })
        return data.data
      }

      // User not found, sign out
      this.signOut()
      return null
    } catch {
      return this.user
    }
  }
}

// ============================================================================
// Singleton & Factory
// ============================================================================

let authStore: AuthStore | null = null

/**
 * Get or create the auth store singleton
 */
export function getAuthStore(): AuthStore {
  if (!authStore) {
    authStore = new AuthStore()
  }
  return authStore
}

/**
 * Create a new auth store (for testing or SSR)
 */
export function createAuthStore(): AuthStore {
  return new AuthStore()
}

/**
 * Reset the singleton auth store
 */
export function resetAuthStore(): void {
  authStore = null
}
